  1	import * as React from 'react';
  2	import * as _ from 'lodash';
  3	import classNames from 'classnames';
  4	import { useTranslation } from 'react-i18next';
  5	import { DomainPropType, DomainTuple } from 'victory-core';
  6	import {
  7	  Chart,
  8	  ChartAxis,
  9	  ChartAxisProps,
 10	  ChartBar,
 11	  ChartGroup,
 12	  ChartThemeColor,
 13	  ChartVoronoiContainer,
 14	} from '@patternfly/react-charts/victory';
 15	import { Alert, Card, CardBody, CardTitle } from '@patternfly/react-core';
 16	import {
 17	  formatDate,
 18	  getXaxisValues,
 19	  hourformat,
 20	  parsePrometheusDuration,
 21	  monthYear,
 22	} from './dateTime';
 23	import { ALL_NAMESPACES_KEY } from '../../consts';
 24	import {
 25	  usePipelineMetricsForAllNamespacePoll,
 26	  usePipelineMetricsForNamespaceForPipelinePoll,
 27	  usePipelineMetricsForNamespacePoll,
 28	} from '../pipelines-metrics/hooks';
 29	import {
 30	  MetricsQueryPrefix,
 31	  PipelineQuery,
 32	  adjustToStartOfWeek,
 33	} from '../pipelines-metrics/utils';
 34	import { LoadingInline } from '../Loading';
 35	
 36	interface PipelinesRunsNumbersChartProps {
 37	  namespace?: string;
 38	  timespan?: number;
 39	  interval?: number;
 40	  domain?: DomainPropType;
 41	  parentName?: string;
 42	  bordered?: boolean;
 43	  width?: number;
 44	}
 45	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 46	
 47	const metricsToSummary = (
 48	  prometheusResult: any,
 49	): { group_value: number; total: number }[] => {
 50	  let summaryResponse = [];
 51	  if (prometheusResult?.data?.result[0]?.values) {
 52	    summaryResponse = prometheusResult?.data?.result[0]?.values.map(
 53	      (value, index, array) => {
 54	        const previousValue = index > 0 ? parseInt(array[index - 1][1]) : 0;
 55	        const currentValue = parseInt(value[1]);
 56	        const total = currentValue - previousValue;
 57	        return {
 58	          group_value: value[0],
 59	          total: total < 0 ? currentValue : total,
 60	        };
 61	      },
 62	    );
 63	    return summaryResponse;
 64	  }
 65	  return summaryResponse;
 66	};
 67	
 68	const getChartData = (
 69	  tickValues: number[] | Date[],
 70	  data: any,
 71	  type: string,
 72	) => {
 73	  const sortedTickValues = tickValues.slice().sort((a, b) => a - b);
 74	  const chartData = sortedTickValues?.map((value, index) => {
 75	    if (index === 0) {
 76	      // Ensure the first value is always 0
 77	      return {
 78	        x: value,
 79	        y: 0,
 80	      };
 81	    }
 82	    const s = data?.find((d) => {
 83	      const group_date = new Date(Number(d.group_value) * 1000);
 84	      if (type == 'hour') {
 85	        return group_date.getHours() === value;
 86	      }
 87	      if (type == 'week') {
 88	        const adjustedGroupDate = adjustToStartOfWeek(new Date(group_date));
 89	        return (
 90	          adjustedGroupDate.toDateString() === new Date(value).toDateString()
 91	        );
 92	      }
 93	      if (type == 'day') {
 94	        return group_date.toDateString() === new Date(value).toDateString();
 95	      }
 96	      if (type == 'month') {
 97	        return group_date.getMonth() === value.getMonth();
 98	      }
 99	    });
100	    return {
101	      x: value,
102	      y: s?.total || 0,
103	    };
104	  });
105	  return chartData;
106	};
107	
108	const PipelineRunsNumbersChartK8s: React.FC<PipelinesRunsNumbersChartProps> = ({
109	  namespace,
110	  timespan,
111	  interval,
112	  domain,
113	  parentName,
114	  bordered,
115	  width = 530,
116	}) => {
117	  const { t } = useTranslation('plugin__pipelines-console-plugin');
118	  const startTimespan = timespan - parsePrometheusDuration('1d');
119	  const endDate = new Date(Date.now()).setHours(0, 0, 0, 0);
120	  const startDate = new Date(Date.now() - startTimespan).setHours(0, 0, 0, 0);
121	  const { x: domainX, y: domainY } = (domain as DomainType) || {};
122	  const domainValue: DomainPropType = {
123	    x: domainX || [startDate, endDate],
124	    y: domainY || undefined,
125	  };
126	  const [pipelineRunsChartError, setPipelineRunsChartError] = React.useState<
127	    string | null
128	  >(null);
129	  const [
130	    runSuccessRatioData,
131	    runSuccessRatioError,
132	    loadingRunSuccessRatioData,
133	  ] =
134	    parentName && namespace
135	      ? usePipelineMetricsForNamespaceForPipelinePoll({
136	          namespace,
137	          timespan,
138	          delay: interval,
139	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
140	          name: parentName,
141	          metricsQuery:
142	            PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE_FOR_PIPELINE,
143	          timeout: 90000,
144	        })
145	      : namespace == ALL_NAMESPACES_KEY
146	      ? usePipelineMetricsForAllNamespacePoll({
147	          timespan,
148	          delay: interval,
149	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
150	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_ALL_NAMESPACE,
151	          timeout: 90000,
152	        })
153	      : usePipelineMetricsForNamespacePoll({
154	          namespace,
155	          timespan,
156	          delay: interval,
157	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
158	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE,
159	          timeout: 90000,
160	        });
161	
162	  const convertToSummaryData = React.useMemo(() => {
163	    if (runSuccessRatioError) {
164	      return [];
165	    }
166	    return metricsToSummary(runSuccessRatioData);
167	  }, [runSuccessRatioData, runSuccessRatioError]);
168	
169	  const [tickValues, type] = getXaxisValues(timespan);
170	
171	  let xTickFormat;
172	  let dayLabel;
173	  let showLabel = false;
174	  let chartData = [];
175	  switch (type) {
176	    case 'hour':
177	      xTickFormat = (d) => hourformat(d);
178	      showLabel = true;
179	      domainValue.x = [0, 23];
180	      dayLabel = formatDate(new Date());
181	      chartData = getChartData(tickValues, convertToSummaryData, 'hour');
182	      break;
183	    case 'day':
184	      xTickFormat = (d) => formatDate(d);
185	      domainValue.x = [startDate, endDate];
186	      chartData = getChartData(tickValues, convertToSummaryData, 'day');
187	      break;
188	    case 'week':
189	      xTickFormat = (d) => formatDate(d);
190	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
191	      chartData = getChartData(tickValues, convertToSummaryData, 'week');
192	      break;
193	    case 'month':
194	      xTickFormat = (d) => monthYear(d);
195	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
196	      chartData = getChartData(tickValues, convertToSummaryData, 'month');
197	      break;
198	    default:
199	      console.log('Received wrong data');
200	      break;
201	  }
202	  const max: number = Math.max(...chartData.map((yVal) => yVal.y));
203	  !isNaN(max) && max > 5
204	    ? (domainValue.y = [0, max])
205	    : (domainValue.y = [0, 5]);
206	
207	  if (!domainY) {
208	    let minY: number = _.minBy(chartData, 'y')?.y ?? 0;
209	    let maxY: number = _.maxBy(chartData, 'y')?.y ?? 0;
210	    if (minY === 0 && maxY === 0) {
211	      minY = -1;
212	      maxY = 1;
213	    } else if (minY > 0 && maxY > 0) {
214	      minY = 0;
215	    } else if (minY < 0 && maxY < 0) {
216	      maxY = 0;
217	    }
218	    domainValue.y = [minY, maxY];
219	  }
220	
221	  let xAxisStyle: ChartAxisProps['style'] = {
222	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
223	  };
224	  const yAxisStyle: ChartAxisProps['style'] = {
225	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
226	  };
227	  if (tickValues.length > 7) {
228	    xAxisStyle = {
229	      tickLabels: {
230	        fill: 'var(--pf-t--global--text--color--regular)',
231	        angle: 320,
232	        fontSize: 10,
233	        textAnchor: 'end',
234	        verticalAnchor: 'end',
235	      },
236	    };
237	  }
238	
239	  React.useEffect(() => {
240	    const hasNonAbortError =
241	      runSuccessRatioError && runSuccessRatioError.name !== 'AbortError';
242	    setPipelineRunsChartError(
243	      hasNonAbortError
244	        ? runSuccessRatioError?.message ?? t('Unable to load pipeline runs')
245	        : null,
246	    );
247	  }, [runSuccessRatioError]);
248	
249	  return (
250	    <>
251	      <Card
252	        className={classNames({
253	          'pipeline-overview__number-of-plr-card':!pipelineRunsChartError,
254	          'card-border': bordered,
255	        })}
256	      >
257	        <CardTitle className="pipeline-overview__number-of-plr-card__title">
258	          <span>{t('Number of PipelineRuns')}</span>
259	        </CardTitle>
260	         <CardBody 
261	          className={classNames({
262	            'pipeline-overview__number-of-plr-card__body':!pipelineRunsChartError,
263	          })}
264	        >
265	          {pipelineRunsChartError ? (
266	            <Alert
267	              variant="danger"
268	              isInline
269	              title={t('Unable to load pipeline runs')}
270	              className="pf-v6-u-mb-md pf-v6-u-mt-lg"
271	            />
272	          ) : (
273	            <div className="pipeline-overview__number-of-plr-card__bar-chart-div">
274	              {loadingRunSuccessRatioData ? (
275	                <LoadingInline />
276	              ) : (
277	                <Chart
278	                  containerComponent={
279	                    <ChartVoronoiContainer
280	                      labels={({ datum }) => `${datum.y}`}
281	                      constrainToVisibleArea
282	                    />
283	                  }
284	                  scale={{ x: 'time', y: 'linear' }}
285	                  domain={domainValue}
286	                  domainPadding={{ x: [30, 25] }}
287	                  height={145}
288	                  width={width}
289	                  padding={{
290	                    top: 10,
291	                    bottom: 55,
292	                    left: 50,
293	                  }}
294	                  themeColor={ChartThemeColor.blue}
295	                >
296	                  <ChartAxis
297	                    tickValues={tickValues}
298	                    style={xAxisStyle}
299	                    tickFormat={xTickFormat}
300	                    label={showLabel ? dayLabel : ''}
301	                  />
302	                  <ChartAxis dependentAxis style={yAxisStyle} />
303	                  <ChartGroup>
304	                    <ChartBar data={chartData} barWidth={18} />
305	                  </ChartGroup>
306	                </Chart>
307	              )}
308	            </div>
309	          )}
310	        </CardBody>
311	      </Card>
312	    </>
313	  );
314	};
315	
316	export default PipelineRunsNumbersChartK8s;

