108	const PipelineRunsNumbersChartK8s: React.FC<PipelinesRunsNumbersChartProps> = ({
109	  namespace,
110	  timespan,
111	  interval,
112	  domain,
113	  parentName,
114	  bordered,
115	  width = 530,
116	}) => {
