142	            PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE_FOR_PIPELINE,
143	          timeout: 90000,
144	        })
145	      : namespace == ALL_NAMESPACES_KEY
146	      ? usePipelineMetricsForAllNamespacePoll({
147	          timespan,
148	          delay: interval,
149	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
150	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_ALL_NAMESPACE,
151	          timeout: 90000,
152	        })
